 if(!caseId||!userId)return Promise.reject(new Error('Select an authorised case before saving a relationship.'));
 const sequence=(relationshipWriteSequences.get(caseId)||0)+1;
 relationshipWriteSequences.set(caseId,sequence);
 const snapshot={caseId,userId,sequence,workspaceId:relationshipWorkspaceIds.get(caseId)||relationshipWorkspaceRecord?.id||null,relationships:[...('relationships' in overrides?overrides.relationships:relationshipRecords)].filter(r=>String(r.caseId)===caseId),tombstones:[...('tombstones' in overrides?overrides.tombstones:relationshipTombstones)],audit:[...('audit' in overrides?overrides.audit:relationshipAudit)],notApplicable:[...('notApplicable' in overrides?overrides.notApplicable:notApplicableMissing)]};
