  const {data,error}=await db.from('case_items').select('*').eq('id',workspaceId).eq('client_id',snapshot.caseId).maybeSingle();
  if(error)throw error;
  const remote=data?.item||{};
  (remote.tombstones||[]).forEach(id=>tombstones.add(id));
  const map=new Map((remote.relationships||[]).filter(r=>String(r.caseId)===snapshot.caseId).map(r=>[r.id,r]));
  merged.forEach(r=>{const prior=map.get(r.id);if(!prior||String(r.updatedAt||r.createdAt)>=String(prior.updatedAt||prior.createdAt))map.set(r.id,r)});
  merged=dedupeRelationshipRecords([...map.values()],tombstones);
