function nativeConnectedType(record){const item=record.item||{},section=normalise(record.section),method=normalise(item.method),type=normalise(item.type),assetDescription=normalise(`${item.assetType} ${item.type} ${item.category} ${item.name} ${item.details} ${item.description}`);if(section==='evidence')return /order/.test(type)?'Court Order':'Evidence';if(section==='facts'||method.includes('identified fact'))return 'Fact';if(section==='issues'||method.includes('disputed issue'))return 'Matter to Resolve';if(section==='timeline')return 'Timeline Event';if(section==='people'||section==='contacts'||['party details','contacts'].includes(normalise(item.category)))return 'Person';if(section==='property')return 'Property';if(section==='assets'){if(/property|house|home|land|flat/.test(assetDescription))return 'Property';return /account|bank|isa|saving|investment/.test(assetDescription)?'Account':'Asset'}if(['bank','finance','accounts'].includes(section))return 'Account';if(section==='transactions')return 'Transaction';if(section==='hearings')return 'Hearing';if(section==='orders')return 'Court Order';if(section==='settlement'||/position/.test(normalise(item.category)))return 'Settlement Position';if(section==='prep')return /missing|obtain|clarify|outstanding|required|gap/.test(normalise(`${item.task} ${item.notes}`))?'Information Still Needed':'Action';return 'Fact'}
