function reviewReceiptKey(){return `crs_publication_receipt_v505_${session?.user?.id||'anonymous'}_${activeCase?.id||'none'}`}
function currentCaseReceipt(){const caseId=String(activeCase?.id||''),userId=String(session?.user?.id||'');if(currentReceipt&&(String(currentReceipt.caseId)!==caseId||(currentReceipt.userId&&String(currentReceipt.userId)!==userId)))currentReceipt=null;if(!currentReceipt&&caseId&&userId)try{const candidate=JSON.parse(sessionStorage.getItem(reviewReceiptKey())||'null');if(candidate&&String(candidate.caseId)===caseId&&(!candidate.userId||String(candidate.userId)===userId))currentReceipt=candidate}catch{}return currentReceipt}
function normaliseReviewProposal(p){const state=p.workflowState||p.state||(p.selected&&p.reviewed?'Approved':p.reviewed?'Reviewed':'Proposed'),destination=reviewDestinations[p.type]||null;return Object.assign(p,{originalDetail:p.originalDetail||p.detail||'',workflowState:state,reviewed:['Reviewed','Approved','Published'].includes(state),selected:state==='Approved',selectedForPublish:Boolean(p.selectedForPublish),sourceDescription:p.sourceDescription||p.item?.source||p.meta||'CourtReady investigation',evidenceStatus:p.evidenceStatus||(/evidence|supported|statement|document/i.test(`${p.type} ${p.meta||''}`)?'Evidence identified':'Support requires review'),supportStatus:p.supportStatus||(/high confidence/i.test(p.meta||'')?'High support':/medium confidence/i.test(p.meta||'')?'Moderate support':'Not assessed'),dateIdentified:p.dateIdentified||p.item?.date||new Date().toISOString().slice(0,10),relatedSection:p.relatedSection||p.section||'',destination:p.destination||destination?.section||'',duplicateDecision:p.duplicateDecision||'skip',publishResult:p.publishResult||null})}
