function proposalCmsRecord(p){const today=new Date().toISOString().slice(0,10),detail=p.detail||'',sourceSystem='investigation-engine-4.0';if(p.type==='Evidence')return {section:'evidence',item:{date:p.dateIdentified||today,title:p.title||'Evidence identified',source:p.sourceDescription||p.item?.source||'CourtReady Case Builder',type:p.item?.type||'Case evidence',relevance:p.item?.relevance||detail,bundleRef:p.item?.evidenceRef||'',notes:detail,sourceSystem}};if(p.type==='Gap'||p.type==='Action')return {section:'prep',item:{task:p.item?.task||p.title||'Investigate missing evidence',owner:p.item?.owner||'You',dueDate:p.item?.dueDate||'',completed:'No',risk:p.item?.risk||'Medium',notes:detail,sourceSystem}};if(p.type==='Chronology')return {section:'timeline',item:{date:p.dateIdentified||p.item?.date||today,event:p.item?.event||detail,category:p.item?.category||'Other',description:detail,importance:'Medium',sourceSystem}};if(p.type==='Issue')return {section:'notes',item:{date:p.dateIdentified||today,method:'CourtReady — Disputed issue',summary:detail||p.title,actionRequired:'Yes',owner:'Case owner',deadline:'',completed:'No',sourceSystem}};return {section:'notes',item:{date:p.dateIdentified||today,method:'CourtReady — Identified fact',summary:detail||p.title,actionRequired:'No',owner:'Case owner',deadline:'',completed:'No',sourceSystem}}}
function recordWording(record){return record?.item?.summary||record?.item?.title||record?.item?.task||record?.item?.event||record?.item?.notes||''}
