function reviewAction(p,action,article){if(action==='edit'){renderReviewEdit(p,article);return}if(action==='approve')p.workflowState='Approved';else if(action==='draft'){p.workflowState='Draft';p.selectedForPublish=false}else if(action==='reject'){p.workflowState='Rejected';p.selectedForPublish=false}else if(action==='not-applicable'){p.workflowState='Rejected';p.notApplicable=true;p.selectedForPublish=false}else if(action==='retry'){p.workflowState='Approved';p.selectedForPublish=true;p.publishResult=null}reviewPersist();renderReviewCentre()}
function renderReviewEdit(p,article){const original={detail:p.detail,type:p.type,dateIdentified:p.dateIdentified,sourceDescription:p.sourceDescription,evidenceStatus:p.evidenceStatus,destination:p.destination};article.innerHTML=`<form class="review-edit-form"><h4>Edit proposed record</h4><label>Main wording<textarea name="detail" rows="5" required>${escapeHtml(p.detail)}</textarea></label><div class="form-grid two-col"><label>Category<select name="type">${Object.entries(reviewCategories).map(([v,l])=>`<option value="${v}" ${p.type===v?'selected':''}>${l}</option>`).join('')}</select></label><label>Date<input name="dateIdentified" type="date" value="${escapeHtml(p.dateIdentified||'')}"></label><label>Source description<input name="sourceDescription" value="${escapeHtml(p.sourceDescription)}"></label><label>Evidence status<select name="evidenceStatus"><option>${escapeHtml(p.evidenceStatus)}</option><option>Evidence identified</option><option>Partially supported</option><option>Unsupported</option><option>Support requires review</option></select></label><label>Intended destination<select name="destination"><option value="${reviewDestinations[p.type]?.section||''}">${reviewDestinations[p.type]?.label||'Requires review'}</option></select></label></div><div class="button-row"><button class="button primary" type="submit">Save</button><button class="button secondary" data-cancel-edit type="button">Cancel</button></div></form>`;const form=article.querySelector('form');form.addEventListener('submit',e=>{e.preventDefault();const data=Object.fromEntries(new FormData(form));Object.assign(p,data,{workflowState:'Reviewed',selectedForPublish:false,destination:reviewDestinations[data.type]?.section||''});reviewPersist();renderReviewCentre()});article.querySelector('[data-cancel-edit]').addEventListener('click',()=>{Object.assign(p,original);renderReviewCentre()});form.elements.detail.focus()}
function renderReviewCentre(){const visible=reviewVisibleItems(),groups=$('reviewGroups');groups.innerHTML='';const all=investigationProposals.map(normaliseReviewProposal),approved=all.filter(p=>p.workflowState==='Approved'),selected=approved.filter(p=>p.selectedForPublish);$('reviewCentreTotals').textContent=`${all.length} total · ${approved.length} approved · ${all.filter(p=>p.workflowState==='Failed').length} failed`;$('reviewPublishCount').textContent=`${selected.length} approved record${selected.length===1?'':'s'} selected`;$('reviewPublishSelected').disabled=!selected.length;if(!visible.length){groups.innerHTML='<div class="empty-intelligence"><strong>No records match these filters.</strong><p>Continue the investigation to identify new facts, issues or evidence gaps, or change the filters.</p><button class="button secondary" type="button" data-empty-investigate>Continue investigation</button></div>';groups.querySelector('button').onclick=openInvestigationEngine;return}Object.entries(reviewCategories).forEach(([type,label])=>{const items=visible.filter(p=>p.type===type);if(!items.length)return;const section=document.createElement('section');section.className='review-group';section.innerHTML=`<h3>${label} <span class="count-chip">${items.length}</span></h3><div class="review-card-list"></div>`;items.forEach(p=>section.querySelector('.review-card-list').appendChild(reviewCard(p)));groups.appendChild(section)})}
function openReviewCentre(){if(!activeCase)return;investigationProposals=generateInvestigationProposals();restoreInvestigationThread();investigationProposals.forEach(normaliseReviewProposal);try{const f=JSON.parse(localStorage.getItem(`crs_review_filters_v505_${activeCase.id}`)||'null');if(f)({reviewStatusFilter,reviewCategoryFilter,reviewSearch}=f)}catch{}$('reviewStatusFilter').value=reviewStatusFilter;$('reviewCategoryFilter').value=reviewCategoryFilter;$('reviewSearch').value=reviewSearch;$('reviewWorkspaceLink').href=$('receiptWorkspaceLink').href=caseWorkspaceUrl();setView('reviewCentrePanel');renderReviewCentre();renderReceipt()}
function summaryCounts(items,keyFn){return items.reduce((a,p)=>{const key=keyFn(p);a[key]=(a[key]||0)+1;return a},{})}
function listCounts(counts){return Object.entries(counts).map(([k,v])=>`<li>${escapeHtml(k)}: <strong>${v}</strong></li>`).join('')||'<li>None</li>'}
function selectedApproved(){return investigationProposals.map(normaliseReviewProposal).filter(p=>p.workflowState==='Approved'&&p.selectedForPublish)}
function openPublishConfirmation(){const selected=selectedApproved();if(!selected.length){$('reviewCentreMessage').textContent='No approved records are selected. Review and approve at least one item before adding information to your case.';return}selected.forEach(detectDuplicate);reviewLastFocus=document.activeElement;$('publishConfirmationIntro').textContent=`You are about to add ${selected.length} approved record${selected.length===1?'':'s'} to ${activeCase.name||'the selected case'} in McKenzieCMS.`;$('publishConfirmationSummary').innerHTML=`<dl><div><dt>Selected case</dt><dd>${escapeHtml(activeCase.name||'Untitled case')}</dd></div><div><dt>Case number</dt><dd>${escapeHtml(activeCase.case_number||'Not recorded')}</dd></div><div><dt>Approved records</dt><dd>${selected.length}</dd></div><div><dt>Blocked</dt><dd>${selected.filter(p=>!reviewDestinations[p.type]).length}</dd></div><div><dt>Still in draft</dt><dd>${investigationProposals.filter(p=>normaliseReviewProposal(p).workflowState==='Draft').length}</dd></div></dl><div class="confirmation-breakdowns"><div><h3>Categories</h3><ul>${listCounts(summaryCounts(selected,p=>reviewCategories[p.type]||p.type))}</ul></div><div><h3>Destinations</h3><ul>${listCounts(summaryCounts(selected,p=>reviewDestinations[p.type]?.label||'Blocked'))}</ul></div><div><h3>Duplicate decisions</h3><ul>${listCounts(summaryCounts(selected,p=>p.duplicateMatch?p.duplicateDecision:'No duplicate'))}</ul></div></div>`;$('publishProgress').textContent='';show('publishConfirmationModal');document.body.classList.add('modal-open');$('cancelPublishTop').focus()}
