function renderGuidedInvestigationSummary(){if(!$('guidedInvestigationGroups'))return;const items=workingIntelligenceProposals(),groups=[['Fact','Important points'],['Evidence','Documents mentioned'],['Chronology','Dates and events'],['Gap','Things that may be missing'],['Issue','Things that are disputed or unclear']],counts=groups.map(([type,label])=>({label,count:items.filter(item=>item.type===type).length})).filter(group=>group.count);$('guidedInvestigationGroups').innerHTML=counts.map(group=>`<article><strong>${group.count}</strong><span>${escapeHtml(group.label)}</span></article>`).join('')||'<p>No identified material yet.</p>';$('guidedInvestigationSummaryText').textContent=items.length?`${items.length} working item${items.length===1?' has':'s have'} been identified. Check the wording before approving anything.`:'Nothing has been identified yet. Add one material event, payment, document or concern above.';$('guidedInvestigationReview').classList.toggle('hidden',!items.length)}
