function refreshGuidedCriticalAttention(){if(!activeCase?.id)return;const failures=guidedReviewItems().filter(item=>item.workflowState==='Failed').length+evidenceRecords.filter(item=>item.workflowState==='Failed').length+(currentReceipt?.results||[]).filter(item=>item.status==='Failed').length;if(!failures)return;const existing=[...$('guidedAttentionList').querySelectorAll('li')].map(item=>item.textContent).filter(text=>!text.startsWith('A previous attempt')),$list=$('guidedAttentionList');$list.innerHTML=[`A previous attempt to add ${failures} item${failures===1?'':'s'} to the case failed and needs review.`,...existing].slice(0,3).map(item=>`<li>${escapeHtml(item)}</li>`).join('');show('guidedAttention');setGuidedDisclosure('guidedReviewPanel')}
function openGuidedEvidenceFilter(filter){openEvidenceWorkspace();evidenceStatusFilter=filter;$('evidenceStatusFilter').value=filter;renderEvidenceWorkspace()}
document.querySelectorAll('#guidedDisclosures .guided-disclosure-toggle').forEach(button=>{button.dataset.guidedDisclosure='';button.addEventListener('click',()=>setGuidedDisclosure(button.getAttribute('aria-expanded')==='true'?'':button.getAttribute('aria-controls'),true))});
$('workspaceModeToggle').addEventListener('click',()=>setWorkspaceMode(workspaceMode==='guided'?'full':'guided',{returnHome:workspaceMode==='full'}));$('guidedNavCases').addEventListener('click',openMyCases);$('guidedNavContinue').addEventListener('click',openDashboard);$('guidedNavEvidence').addEventListener('click',openEvidenceWorkspace);$('guidedNavReview').addEventListener('click',openReviewCentre);$('guidedNextAction').addEventListener('click',()=>guidedPrimaryAction?.());$('guidedEvidenceAction').addEventListener('click',openEvidenceWorkspace);$('guidedTimelineAction').addEventListener('click',()=>openConnectedCase({type:'Timeline Events'}));$('guidedResolveAction').addEventListener('click',()=>openConnectedCase({view:'missing'}));$('guidedReviewAction').addEventListener('click',openReviewCentre);$('guidedHealthDetails').addEventListener('click',openCaseHealthReport);$('guidedFullIntelligence').addEventListener('click',()=>{setWorkspaceMode('full');openDashboard();setTimeout(()=>{$('caseIntelligenceHeading').scrollIntoView({block:'start'});$('caseIntelligenceHeading').focus()},0)});$('guidedConnected').addEventListener('click',()=>openConnectedCase());$('guidedPublicationHistory').addEventListener('click',()=>{openReviewCentre();if(currentReceipt)renderReceipt(true)});$('guidedDetailedEvidence').addEventListener('click',()=>{setWorkspaceMode('full');openEvidenceWorkspace()});$('guidedInvestigationReview').addEventListener('click',openReviewCentre);$('guidedUnlinkedEvidence').addEventListener('click',()=>openGuidedEvidenceFilter('Unsupported facts'));$('guidedMissingDocuments').addEventListener('click',()=>openGuidedEvidenceFilter('Missing documents'));
