function assetScheduleHealthData(){const empty={total:0,missingValues:0,withoutEvidence:0,disputedOwnership:0,disputedValuation:0,missingLiabilities:0};if(!activeCase?.id)return empty;try{const saved=JSON.parse(localStorage.getItem(`crs_asset_schedule_v52_${activeCase.id}`)||'null'),assets=Array.isArray(saved?.assets)?saved.assets:[],liabilityCategories=new Set(['Loans Owed By Parties','Credit Cards','Mortgages','Other Liabilities']),hasValue=asset=>['applicantFigure','respondentFigure','evidenceFigure','workingFigure','grossValue','netValue'].some(field=>asset[field]!==''&&asset[field]!==null&&asset[field]!==undefined);return {total:assets.length,missingValues:assets.filter(asset=>!hasValue(asset)).length,withoutEvidence:assets.filter(asset=>!asset.documentTitle&&!asset.supportingDocuments?.length&&!asset.relatedEvidence?.length).length,disputedOwnership:assets.filter(asset=>asset.ownership==='Disputed').length,disputedValuation:assets.filter(asset=>['Disputed','Multiple Figures'].includes(asset.valuationStatus)).length,missingLiabilities:assets.filter(asset=>liabilityCategories.has(asset.category)&&(asset.liability===''||asset.liability===null||asset.liability===undefined)&&(asset.workingFigure===''||asset.workingFigure===null||asset.workingFigure===undefined)).length}}catch{return empty}}
function renderAssetCaseHealth(){if(!$('assetCaseHealthIndicators'))return;const health=assetScheduleHealthData(),items=[['Records',health.total],['Missing values',health.missingValues],['Without evidence',health.withoutEvidence],['Ownership disputed',health.disputedOwnership],['Valuation disputed',health.disputedValuation],['Missing liabilities',health.missingLiabilities]];$('assetCaseHealthIndicators').innerHTML=items.map(([label,count])=>`<article><strong>${count}</strong><span>${label}</span></article>`).join('');$('guidedAssetsSummary').textContent=health.total?`${health.total} working record${health.total===1?'':'s'} · ${health.missingValues+health.withoutEvidence} need value or evidence review`:'No working asset records yet'}
const renderCaseIntelligenceV52=renderCaseIntelligence;
