function renderNeedsGuidedSummary(){if(!activeCase?.id||!$('guidedNeedsSummary'))return;try{const saved=JSON.parse(localStorage.getItem(`crs_needs_affordability_v53_${activeCase.id}`)||'null'),rows=Object.values(saved?.rows||{}),figures=rows.filter(row=>row.applicant!==''||row.respondent!=='').length,unsourced=rows.filter(row=>(row.applicant!==''&&!row.applicantSource)||(row.respondent!==''&&!row.respondentSource)).length;$('guidedNeedsSummary').textContent=figures?`${figures} categor${figures===1?'y':'ies'} recorded · ${unsourced} need source review`:'No affordability figures recorded yet'}catch{$('guidedNeedsSummary').textContent='No affordability figures recorded yet'}}
