function renderPensionGuidedSummary(){if(!activeCase?.id||!$('guidedPensionsSummary'))return;try{const saved=JSON.parse(localStorage.getItem(`crs_pension_analysis_v54_${activeCase.id}`)||'null'),records=Array.isArray(saved?.records)?saved.records:[],review=records.filter(record=>!record.documentTitle||(!record.cetvDate&&record.schemeType!=='State Pension')).length;$('guidedPensionsSummary').textContent=records.length?`${records.length} pension record${records.length===1?'':'s'} · ${review} need evidence review`:'No pension records yet'}catch{$('guidedPensionsSummary').textContent='No pension records yet'}}
