const renderEvidenceWorkspaceV51=renderEvidenceWorkspace;
renderEvidenceWorkspace=function(){renderEvidenceWorkspaceV51();renderGuidedEvidenceOverview();const visible=evidenceVisible(),cards=[...$('evidenceWorkspaceList').querySelectorAll('.evidence-record-card:not(.published-evidence-readback)')];cards.slice(0,visible.length).forEach((card,index)=>{if(card.querySelector('.guided-evidence-card-summary'))return;const evidence=visible[index],summary=document.createElement('p');summary.className='guided-evidence-card-summary guided-only';summary.textContent=[evidence.documentDate&&`Dated ${evidence.documentDate}`,`${evidence.links.length} connection${evidence.links.length===1?'':'s'}`,evidence.workflowState].filter(Boolean).join(' · ');card.querySelector('h3')?.after(summary)});const native=evidenceNativeVisible(),nativeCards=[...$('evidenceWorkspaceList').querySelectorAll('.published-evidence-readback')];nativeCards.slice(0,native.length).forEach((card,index)=>{if(card.querySelector('.guided-evidence-card-summary'))return;const record=native[index],summary=document.createElement('p'),relationships=record.item?.courtReadyEvidence?.relationships?.length||0;summary.className='guided-evidence-card-summary guided-only';summary.textContent=[record.item?.date&&`Dated ${record.item.date}`,`${relationships} connection${relationships===1?'':'s'}`,'Added to case'].filter(Boolean).join(' · ');card.querySelector('h3')?.after(summary)})};
